```{.r .cell-code}
library(rlang)


# gt save function
gt_save_crop <- function(data,
                         file = NULL,
                         bg = "white",
                         whitespace = 50,
                         zoom = 2,
                         expand = 5) {
  tmp <- tempfile(fileext = ".png")

  # Wrap the gtsave_extra call in a tryCatch to handle errors
  tryCatch({
    gtExtras::gtsave_extra(data, tmp, zoom = zoom, expand = expand)
  }, error = function(e) {
    # If there's an error, try using regular gt::gtsave instead
    message("gtsave_extra failed, trying gt::gtsave...")
    gt::gtsave(data, tmp, zoom = zoom, expand = expand)
  })

  magick::image_read(tmp) |> 
    magick::image_trim() |> 
    magick::image_border(bg, glue::glue('{whitespace}x{whitespace}')) |> 
    magick::image_write(file)
  unlink(tmp)
}

# load processed games
games <- readr::read_csv("cfb_games_25.csv")

games_processed <- games |>
  dplyr::mutate(
    date = as.Date(game_date),
    # Define P4 conferences
    # home_is_p4 = homeConfShort %in% c("ACC", "SEC", "B12", "B10"),
    # away_is_p4 = awayConfShort %in% c("ACC", "SEC", "B12", "B10"),
    type = dplyr::case_when(
      homeClassification == "fcs" |
        awayClassification == "fcs" ~ "FCS Games",
      conferenceGame == TRUE ~ "Conference Games",
      conferenceGame == FALSE ~ "Non-Conference Games",
      TRUE ~ "Other"
    )
  ) |>
  dplyr::filter(type != "Other")


games_by_type <- games_processed |>
  dplyr::distinct(id, .keep_all = TRUE) |>
  dplyr::group_by(date, type) |>
  dplyr::summarise(count = dplyr::n(), .groups = "drop") |>
  tidyr::complete(date = seq(min(date), max(date), by = "day"),
                  type,
                  fill = list(count = 0)) |>
  dplyr::group_by(type) |>
  dplyr::arrange(date, .by_group = TRUE) |>
  dplyr::mutate(cumulative = cumsum(count)) |>
  dplyr::ungroup()

# count the teams in each conference 
conference_team_counts <- games |>
  dplyr::filter(
    !is.na(homeConference),
    homeClassification == "fbs"  # Only count FBS teams
  ) |>
  dplyr::select(homeTeam, homeConference) |>
  dplyr::distinct() |>
  dplyr::group_by(homeConference) |>
  dplyr::summarise(total_teams = dplyr::n(), .groups = "drop") |>
  dplyr::rename(conference = homeConference)

# conference counts
conference_weekly_counts <- games |>
  dplyr::filter(
    !is.na(homeConference),!is.na(awayConference),!is.na(week),
    homeClassification == "fbs",
    awayClassification == "fbs"
  ) |>
  dplyr::mutate(conference = homeConference) |>
  dplyr::group_by(conference, week) |>
  dplyr::summarise(
    total_games = dplyr::n(),
    conference_games = sum(conferenceGame == TRUE, na.rm = TRUE),
    .groups = "drop"
  ) |>
  dplyr::select(conference, week, conference_games) |>
  tidyr::pivot_wider(names_from = week,
                     values_from = conference_games,
                     names_prefix = "Week_") |>
  dplyr::mutate(dplyr::across(dplyr::starts_with("Week_"), ~ ifelse(is.na(.x), 0, .x))) |>
  dplyr::select(conference,
                dplyr::starts_with("Week_0"),
                dplyr::everything()) |> 
  dplyr::left_join(conference_team_counts, 
                   by = "conference")
```
:::


### Geom smooth


::: {.cell}

```{.r .cell-code}
type_plot <- games_by_type |>
  ggplot2::ggplot(ggplot2::aes(x = date, y = cumulative, color = type)) +
  ggplot2::geom_smooth(linewidth = 1.2,
                       se = FALSE,
                       method = "loess") +
  ggplot2::scale_x_date(date_labels = "%B", date_breaks = "1 month") +
  ggplot2::scale_y_continuous(limits = c(0, 550), breaks = seq(0, 550, by = 50)) +
  ggplot2::scale_color_manual(
    values = c(
      "Conference Games" = "#e66101",
      "Non-Conference Games" = "#1f78b4",
      "FCS Games" = "#5d4e75",
      "P4 vs P4 Games" = "#d62728"
    )
  ) +
  ggplot2::labs(
    title = "2025 College Football Season <br>Cumulative Games by Type",
    subtitle = paste0(
      "<span style='color: #e66101;'>Conference Games</span><br>",
      "<span style='color: #1f78b4;'>Non-Conference Games</span><br>",
      "<span style='color: #5d4e75;'>Games with FCS opponents</span><br>"
    ),
    caption = "Viz by Chris at Bless your Chart <br> data via collegefootballdata.com",
    x = "",
    y = "Number of Games",
    color = "Game Type"
  ) +
  ggthemes::theme_wsj() +
  ggplot2::geom_vline(
    xintercept = as.Date("2025-09-10"),
    linetype = "dashed",
    color = "#acacac",
    size = 1
  ) +
  ggplot2::theme(
    plot.title = ggtext::element_markdown(
      size = 18,
      face = 'bold',
      family = 'mono'
    ),
    plot.subtitle = ggtext::element_markdown(
      size = 14,
      family = 'mono',
      face = 'bold'
    ),
    legend.position = "none",
    panel.grid.minor = ggplot2::element_blank(),
    plot.caption = ggtext::element_markdown(
      size = 7,
      family = 'mono',
      face = 'bold'
    )
  )

ggplot2::ggsave(
  "game_type_plot.png",
  type_plot,
  w = 7.5,
  h = 9,
  dpi = 600,
  type = 'cairo',
  bg = "white"
)

