     </div>
   </div>
  <br>"
)

week_labels <- setNames(as.character(0:14), paste0("Week_", 0:14))

conf_tbl <- conference_weekly_counts |>
  dplyr::filter(!conference %in% c("Pac-12", "FBS Independents")) |>
  dplyr::select(-Week_16) |>
  dplyr::mutate(
    conference = dplyr::case_match(
      conference,
      "American Athletic" ~ "American",
      "Conference USA" ~ "CUSA",
      "Mid-American" ~ "MAC",
      conference ~ conference
    ),
    total_teams = paste0(total_teams, " ", "teams")
  ) |>
  gt::gt() |>
  gtUtils::gt_theme_gtutils() |>
  gtExtras::gt_merge_stack(
    col1 = "conference",
    col2 = "total_teams",
    palette = c("black", "#848484"),
    small_cap = FALSE
  ) |> 
  gt::cols_align(conference, align = "left") |>
  gtUtils::gt_column_subheaders(
    conference = list(heading = "Conference", subtitle = "# of teams"),
    heading_color = "black",
    subtitle_color = "gray"
  ) |>
  gt::cols_label(.list = week_labels) |>
  gtUtils::gt_border_grid(color = "black",
                          weight = 0.5,
                          include_labels = FALSE) |>
  gtExtras::gt_add_divider(
    columns = c(conference),
    sides = "right",
    color = "black"
  ) |>
  gt::tab_spanner(columns = c(-conference), label = "Week") |>
  gt::data_color(
    columns = c(-conference),
    direction = c("column"),
    method = c("numeric"),
    palette = c("#d7191c", "#fdae61", "#ffffbf", "#a6d96a", "#1a9641"),
    domain = c(0, 9),
    alpha = 0.6
  ) |>
  gt::tab_header(title = gt::html(custom_header)) |>
  gt::tab_source_note(
    source_note =
      gt::html(
        "<hr>Data via collegefootballdata.com | theme via {gtUtils} <br>
        Only regular season conference games through end of November 2025 shown<br>
        <hr><b>Table by Chris at Bless your chart</b>"
      )
  ) |>
  gtUtils::gt_border_bars_bottom(c("#636363", "#969696", "#cccccc")) |>
  gt::tab_options(table.width = gt::px(500)) |>
  gt::tab_style(
    locations = gt::cells_source_notes(),
    style = gt::cell_text(
      font = gt::google_font("Signika Negative"),
