### Faceted by conference


::: {.cell}

```{.r .cell-code}
games_processed <- games |>
  dplyr::mutate(
    date = as.Date(game_date),
    type = dplyr::case_when(
      homeClassification == "fcs" |
        awayClassification == "fcs" ~ "FCS Games",
      conferenceGame == TRUE ~ "Conference Games",
      conferenceGame == FALSE ~ "Non-Conference Games",
      TRUE ~ "Other"
    )
  ) |>
  dplyr::filter(type != "Other")

home_games <- games_processed |>
  dplyr::select(id, date, type, conference = homeConference)

away_games <- games_processed |>
  dplyr::select(id, date, type, conference = awayConference)

games_by_conf <- dplyr::bind_rows(home_games, away_games) |>
  dplyr::filter(!is.na(conference) & conference != "")


games_by_conference_type <- games_by_conf |>
  dplyr::distinct(id, conference, .keep_all = TRUE) |>
  dplyr::group_by(date, conference, type) |>
  dplyr::summarise(count = dplyr::n(), .groups = "drop") |>
  tidyr::complete(date = seq(min(games_processed$date), max(games_processed$date), by = "day"),
                  conference,
                  type,
                  fill = list(count = 0)) |>
  dplyr::group_by(conference, type) |>
  dplyr::arrange(date, .by_group = TRUE) |>
  dplyr::mutate(cumulative = cumsum(count)) |>
  dplyr::ungroup() |>
  dplyr::left_join(conference_team_counts, by = "conference") |>   dplyr::filter(
    conference %in% c(
      "ACC",
      "American Athletic",
      "Big 12",
      "Big Ten",
      "Conference USA",
      "Mid-American",
      "Mountain West",
      "SEC",
      "Sun Belt"
    )
  )

# Create the faceted plot
conf_facet_plot <- games_by_conference_type |>
  dplyr::mutate(conf_display = paste0(conference, "\n", total_teams, " teams"),
                conf_display = forcats::fct_reorder(conf_display, total_teams, .desc = TRUE)) |>
  ggplot2::ggplot(ggplot2::aes(x = date, y = cumulative, color = type)) +
  ggplot2::geom_smooth(
    linewidth = 0.8,
    se = FALSE,
    method = "loess",
    span = 0.7
  ) +
  ggplot2::facet_wrap(~ conf_display, scales = "fixed", ncol = 3) +
  ggplot2::scale_x_date(date_labels = "%b", date_breaks = "1 month") +
  ggplot2::scale_y_continuous(limits = c(0, 85), breaks = c(0, 20, 40, 60, 80)) +
  ggplot2::scale_color_manual(
    values = c(
      "Conference Games" = "#e66101",
      "Non-Conference Games" = "#1f78b4",
      "FCS Games" = "#5d4e75"
    )
  ) +
  ggplot2::labs(
    title = "2025 College Football Season<br>Cumulative Games by Type and Conference",
    subtitle = paste0(
      "<span style='color: #e66101;'>Conference Games</span> | ",
      "<span style='color: #1f78b4;'>Non-Conference Games</span> | ",
      "<span style='color: #5d4e75;'>Games with FCS opponents</span>"
    ),
    caption = "Viz by Chris at Bless your Chart <br> data via collegefootballdata.com",
    x = "",
    y = "Cumulative Games",
    color = "Game Type"
  ) +
  ggthemes::theme_wsj() +
  ggplot2::geom_vline(
    xintercept = as.Date("2025-09-10"),
    linetype = "dashed",
    color = "#acacac",
    size = 0.5,
    alpha = 0.7
  ) +
  ggplot2::theme(
    plot.title = ggtext::element_markdown(
      size = 16,
      face = 'bold',
      family = 'mono'
    ),
    plot.subtitle = ggtext::element_markdown(
      size = 12,
      family = 'mono',
      face = 'bold'
    ),
    legend.position = "none",
    panel.grid.minor = ggplot2::element_blank(),
    plot.caption = ggtext::element_markdown(
      size = 8,
      family = 'mono',
      face = 'bold'
    ),
    strip.text = ggplot2::element_text(
      size = 10,
      face = 'bold',
      family = 'mono'
    ),
    axis.text.x = ggplot2::element_text(size = 8),
    axis.text.y = ggplot2::element_text(size = 8)
  )

ggplot2::ggsave(
  "conf_type_plot.png",
  conf_facet_plot,
  w = 7.5,
  h = 9,
  dpi = 600,
  type = 'cairo',
  bg = "white"
)

